mapper.select:
select * from (
	select /*+index_desc(tbl_board pk_board) */ 
	rownum rn, bno, writer, title, content, regdate, updatedate
	from tbl_board
	where 
	
		
			title like #{keyword}
		
		
			writer like #{keyword}
		
		
			content like #{keyword}
		
	
	0  <  bno and 0  <  rownum and rownum  <=  (#{pageNum} * #{amount})
)
where (#pageNum} - 1) * #{amount}   < rn
